// Generate report date range
const now = new Date();
const yesterday = new Date(now);
yesterday.setDate(yesterday.getDate() - 1);

const formatDate = (d) => d.toISOString().split('T')[0];

return [{
  json: {
    report_date: formatDate(now),
    period_start: formatDate(yesterday),
    period_end: formatDate(now),
    report_type: 'daily_summary',
    generated_at: now.toISOString()
  }
}];

// Build the report
const tasks = $input.all()[0]?.json || {};
const chat = $input.all()[1]?.json || {};
const usage = $input.all()[2]?.json || {};

const reportDate = new Date().toISOString().split('T')[0];

const report = {
  report_date: reportDate,
  summary: {
    total_tasks: tasks.total_tasks || 0,
    completed_tasks: tasks.completed_tasks || 0,
    pending_tasks: tasks.pending_tasks || 0,
    failed_tasks: tasks.failed_tasks || 0,
    active_conversations: chat.message_count || 0,
    total_n8n_runs: usage.total_runs || 0,
    total_api_calls: usage.api_calls || 0
  },
  sections: [
    {
      title: 'Task Pipeline',
      content: `${tasks.completed_tasks || 0} completed, ${tasks.pending_tasks || 0} pending, ${tasks.failed_tasks || 0} failed`
    },
    {
      title: 'Chat Activity',
      content: `${chat.message_count || 0} messages exchanged across active conversations`
    },
    {
      title: 'System Usage',
      content: `${usage.total_runs || 0} automation runs, ${usage.api_calls || 0} API calls`
    }
  ],
  generated_at: new Date().toISOString()
};

return [{ json: report }];

